sql:
SELECT COUNT(*) AS total_meters
FROM energy_meters
WHERE location = 'Building A';

SELECT location, COUNT(*) AS meter_count
FROM energy_meters
GROUP BY location;

external_knowledge:
'Currently in use' refers to meters whose status is 'active'.;
Identifiers refer to the names of the energy meters.;
Whereabouts refer to the locations where the energy meters are installed.

- "power usage during the day" refers to hourly energy consumption;
- "identities and locations" of meters refer to their names and installation addresses;
- "highest power usage" means the top 3 meters with the highest average energy consumption;
- "consume more than 500 units hourly" specifies that the energy consumption should be greater than 500 units.

sql:
SELECT AVG(watts) AS average_energy_consumption
FROM measurements
WHERE meter_id = 1 AND timestamp BETWEEN '2023-01-01' AND '2023-12-31';

SELECT AVG(energy_consumption) AS average_energy_consumption
FROM Energy_Consumption_Trends
WHERE meter_id = 1 AND time_interval = 3600;

external_knowledge:
First meter refers to meter_id = 1;
Average power usage pertains to the average wattage;
Throughout the month of April refers to the period from April 1st to April 30th in 2023.

sql:
SELECT meter_id, AVG(energy_consumption) AS average_energy_consumption
FROM Energy_Consumption_Trends
GROUP BY meter_id;

SELECT meter_id, COUNT(alert_id) AS total_alerts
FROM Alerts
GROUP BY meter_id;

SELECT COUNT(*) AS active_meters
FROM energy_meters
WHERE status = 'active';

external_knowledge:
- 'Statue of Liberty' is a metaphor for New York; 
- 'daily energy consumption heartbeat' refers to the average energy consumption over a daily time interval;
- 'meter' metaphorically represents the energy meter.

sql:
SELECT meter_name
FROM energy_meters
WHERE meter_id = 1;

SELECT meter_id, energy_consumption
FROM Energy_Consumption_Trends
ORDER BY energy_consumption DESC;
